/// <summary>
/// extension class for table <c>ITMCostTrans</c>
/// </summary>
[ExtensionOf(tableStr(ITMCostTrans))]
internal final class ETGITMCostTrans_Table_Extension
{
}

Method.Source:
public static boolean existEstimatedOutETG(Common _source)
{
    ITMCostAllocateTrans shipCostAllocateTrans;

    select firstOnly RecId from shipCostAllocateTrans
        where shipCostAllocateTrans.RefTableId == _source.TableId
            && shipCostAllocateTrans.RefRecId == _source.RecId
            && shipCostAllocateTrans.Estimated
            && !shipCostAllocateTrans.Reversed;

    return shipCostAllocateTrans.RecId != 0;
}

internal static boolean existUninvoicedOutETG(Common _source)
{
    ITMCostTrans shipCostTrans;
    ITMCostInvoiceTrans shipCostInvoiceTrans;

    select firstOnly RecId from shipCostTrans
        where shipCostTrans.TransTableId == _source.TableId
            && shipCostTrans.TransRecId == _source.RecId
        notExists join shipCostInvoiceTrans
            where shipCostInvoiceTrans.RefTableId == shipCostTrans.TableId
                && shipCostInvoiceTrans.RefRecId == shipCostTrans.RecId;

    return shipCostTrans.RecId != 0;
}
